 6→export const navigateHandler: SDUIActionHandler = (
 7→  payload,
 8→  _actionContext,
 9→  deps,
10→): SDUIActionResult => {
11→  if (!deps.navigation) {
12→    return { success: false, error: 'Navigation dependency not provided' };
13→  }
14→  if (!payload?.screen || typeof payload.screen !== 'string') {
15→    return { success: false, error: 'Navigate action requires a "screen" string in payload' };
16→  }
17→  deps.navigation.navigate(
18→    payload.screen,
19→    payload.params as Record<string, unknown> | undefined,
20→  );
21→  return { success: true };
22→};
