  1→import type {
  2→  SDUIActionDescriptor,
  3→  SDUIActionContext,
  4→  SDUIActionDeps,
  5→  SDUIActionHandler,
  6→  SDUIActionRegistry,
  7→  SDUIActionResult,
  8→  SDUIContext,
  9→} from '../models';
 10→import { interpolateDeep } from '../utils/interpolation';
 11→
 12→const ANALYTICS_ACTIONS: ReadonlySet<string> = new Set([
 13→  'trackScreenView',
 14→  'trackSelect',
 15→  'trackModalView',
 16→]);
 17→
 18→export function createActionRegistry(
 19→  initial?: SDUIActionRegistry,
 20→): SDUIActionRegistry {
 21→  return { ...initial };
 22→}
 23→
 24→export function registerAction(
 25→  registry: SDUIActionRegistry,
 26→  type: string,
 27→  handler: SDUIActionHandler,
 28→): SDUIActionRegistry {
 29→  return { ...registry, [type]: handler };
 30→}
 31→
 32→export function getActionHandler(
 33→  registry: SDUIActionRegistry,
 34→  type: string,
 35→): SDUIActionHandler | undefined {
 36→  return registry[type];
 37→}
 38→
 39→function buildMergedContext(actionContext: SDUIActionContext): SDUIContext {
 40→  return {
 41→    ...actionContext.screen,
 42→    form: actionContext.form as unknown as SDUIContext,
 43→  };
 44→}
 45→
 46→export async function executeAction(
 47→  registry: SDUIActionRegistry,
 48→  descriptor: SDUIActionDescriptor,
 49→  actionContext: SDUIActionContext,
 50→  deps: SDUIActionDeps,
 51→): Promise<SDUIActionResult> {
 52→  const handler = registry[descriptor.type];
 53→  if (!handler) {
 54→    if (__DEV__) {
 55→      console.warn(`[SDUI] Unknown action type: "${descriptor.type}"`);
 56→    }
 57→    return { success: false, error: `Unknown action type: "${descriptor.type}"` };
 58→  }
 59→
 60→  const mergedContext = buildMergedContext(actionContext);
 61→  const interpolatedPayload = descriptor.payload
 62→    ? interpolateDeep(descriptor.payload, mergedContext)
 63→    : undefined;
 64→
 65→  try {
 66→    return await handler(interpolatedPayload, actionContext, deps);
 67→  } catch (err) {
 68→    const message = err instanceof Error ? err.message : String(err);
 69→    if (__DEV__) {
 70→      console.error(`[SDUI] Action "${descriptor.type}" threw:`, message);
 71→    }
 72→    return { success: false, error: message };
 73→  }
 74→}
 75→
 76→export async function executeActions(
 77→  registry: SDUIActionRegistry,
 78→  descriptors: SDUIActionDescriptor[],
 79→  actionContext: SDUIActionContext,
 80→  deps: SDUIActionDeps,
 81→): Promise<SDUIActionResult[]> {
 82→  const results: SDUIActionResult[] = new Array(descriptors.length);
 83→
 84→  const analyticsIndices: number[] = [];
 85→  const primaryIndices: number[] = [];
 86→
 87→  for (let i = 0; i < descriptors.length; i++) {
 88→    if (ANALYTICS_ACTIONS.has(descriptors[i].type)) {
 89→      analyticsIndices.push(i);
 90→    } else {
 91→      primaryIndices.push(i);
 92→    }
 93→  }
 94→
 95→  for (const i of primaryIndices) {
 96→    if (deps.signal?.aborted) {
 97→      results[i] = { success: false, error: 'Aborted' };
 98→      continue;
 99→    }
100→    results[i] = await executeAction(registry, descriptors[i], actionContext, deps);
101→  }
102→
103→  for (const i of analyticsIndices) {
104→    results[i] = await executeAction(registry, descriptors[i], actionContext, deps);
105→  }
106→
107→  return results;
108→}
